import React from 'react';
import Header from '../components/Header';

const Home = () => {
  const containerStyle = {
    maxWidth: '1400px',
    margin: '0 auto',
    padding: '2rem'
  };

  const titleStyle = {
    fontSize: '1.8rem',
    fontWeight: 600,
    marginBottom: '2rem',
    color: '#eacece',
    borderLeft: '5px solid #8b1e1e',
    paddingLeft: '1rem'
  };

  const gridStyle = {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))',
    gap: '2rem'
  };

  const cardStyle = {
    background: '#141111',
    borderRadius: '24px',
    overflow: 'hidden',
    cursor: 'pointer',
    border: '1px solid #2f1c1c',
    transition: 'transform 0.3s'
  };

  const posterStyle = {
    height: '320px',
    background: 'linear-gradient(145deg, #2c1414 0%, #1f0f0f 100%)',
    display: 'flex',
    alignItems: 'flex-end',
    justifyContent: 'center',
    padding: '2rem'
  };

  const title = {
    padding: '1rem',
    textAlign: 'center',
    color: '#eacece'
  };

  const movies = [
    { id: 1, title: 'Эдвард руки-ножницы', year: 1990 },
    { id: 2, title: 'Прислуга', year: 2011 },
    { id: 3, title: 'Красотка на всю голову', year: 2018 },
  ];

  return (
    <>
      <Header />
      <main style={containerStyle}>
        <h2 style={titleStyle}>🔴 КАТАЛОГ ФИЛЬМОВ</h2>
        <div style={gridStyle}>
          {movies.map(movie => (
            <div key={movie.id} style={cardStyle}>
              <div style={posterStyle}>
                <span style={{ background: 'rgba(0,0,0,0.7)', padding: '0.5rem 1rem', borderRadius: '12px', color: '#d47b7b' }}>
                  {movie.title.toUpperCase()}
                </span>
              </div>
              <div style={title}>
                {movie.title}
                <span style={{ color: '#a16565', marginLeft: '0.5rem' }}>({movie.year})</span>
              </div>
            </div>
          ))}
        </div>
      </main>
    </>
  );
};

export default Home;
